import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"平台整合：多種協定接入 | Antigravity-Manager","description":"學習 Antigravity Tools 的平台協定接入方法。支援 OpenAI、Anthropic、Gemini 等 7 種協定的統一 API 閘道轉換。","frontmatter":{"title":"平台整合：多種協定接入 | Antigravity-Manager","sidebarTitle":"接入你的 AI 平台","subtitle":"平台整合：多種協定接入","description":"學習 Antigravity Tools 的平台協定接入方法。支援 OpenAI、Anthropic、Gemini 等 7 種協定的統一 API 閘道轉換。","order":200},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/platforms/index.md"}'),o={name:"zh-tw/lbjlaq/Antigravity-Manager/platforms/index.md"};function i(l,t,n,h,s,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="平台與整合" tabindex="-1">平台與整合 <a class="header-anchor" href="#平台與整合" aria-label="Permalink to &quot;平台與整合&quot;">​</a></h1><p>Antigravity Tools 的核心能力是把多家 AI 平台的協定轉換為統一的本地 API 閘道。本章節詳細介紹每種協定的接入方式、相容邊界和最佳實踐。</p><h2 id="本章包含" tabindex="-1">本章包含 <a class="header-anchor" href="#本章包含" aria-label="Permalink to &quot;本章包含&quot;">​</a></h2><table tabindex="0"><thead><tr><th>教程</th><th>說明</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI 相容 API</a></td><td><code>/v1/chat/completions</code> 與 <code>/v1/responses</code> 的落地方案，讓 OpenAI SDK 無感接入</td></tr><tr><td><a href="./anthropic/">Anthropic 相容 API</a></td><td><code>/v1/messages</code> 與 Claude Code 的關鍵契約，支撐思維鏈、系統提示詞等核心能力</td></tr><tr><td><a href="./gemini/">Gemini 原生 API</a></td><td><code>/v1beta/models</code> 以及 Google SDK 的端點接入，支援 <code>x-goog-api-key</code> 相容</td></tr><tr><td><a href="./imagen/">Imagen 3 圖片生成</a></td><td>OpenAI Images 參數 <code>size</code>/<code>quality</code> 的自動映射，支援任意寬高比</td></tr><tr><td><a href="./audio/">音訊轉錄</a></td><td><code>/v1/audio/transcriptions</code> 的限制與大封包處理</td></tr><tr><td><a href="./mcp/">MCP 端點</a></td><td>把 Web Search/Reader/Vision 作為可呼叫工具暴露出去</td></tr><tr><td><a href="./cloudflared/">Cloudflared 隧道</a></td><td>一鍵把本地 API 安全暴露到公網（並非預設安全）</td></tr></tbody></table><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推薦順序</p><ol><li><strong>先學你要用的協定</strong>：如果你用 Claude Code，先看 <a href="./anthropic/">Anthropic 相容 API</a>；如果用 OpenAI SDK，先看 <a href="./openai/">OpenAI 相容 API</a></li><li><strong>再學 Gemini 原生</strong>：了解 Google SDK 的直接接入方式</li><li><strong>按需學習擴充功能</strong>：圖片生成、音訊轉錄、MCP 工具</li><li><strong>最後學隧道</strong>：需要公網暴露時再看 <a href="./cloudflared/">Cloudflared 隧道</a></li></ol></div><p><strong>快速選擇</strong>：</p><table tabindex="0"><thead><tr><th>你的場景</th><th>推薦先看</th></tr></thead><tbody><tr><td>使用 Claude Code CLI</td><td><a href="./anthropic/">Anthropic 相容 API</a></td></tr><tr><td>使用 OpenAI Python SDK</td><td><a href="./openai/">OpenAI 相容 API</a></td></tr><tr><td>使用 Google 官方 SDK</td><td><a href="./gemini/">Gemini 原生 API</a></td></tr><tr><td>需要 AI 畫圖</td><td><a href="./imagen/">Imagen 3 圖片生成</a></td></tr><tr><td>需要語音轉文字</td><td><a href="./audio/">音訊轉錄</a></td></tr><tr><td>需要聯網搜尋/網頁閱讀</td><td><a href="./mcp/">MCP 端點</a></td></tr><tr><td>需要遠端存取</td><td><a href="./cloudflared/">Cloudflared 隧道</a></td></tr></tbody></table><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><ul><li>已完成 <a href="./../start/installation/">安裝與升級</a></li><li>已完成 <a href="./../start/add-account/">新增帳號</a></li><li>已完成 <a href="./../start/proxy-and-first-client/">啟動本地反代</a>（至少能存取 <code>/healthz</code>）</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>學完本章節後，你可以繼續學習：</p><ul><li><a href="./../advanced/">進階設定</a>：模型路由、配額治理、高可用排程等進階功能</li><li><a href="./../faq/">常見問題</a>：遇到 401/404/429 等錯誤時的排查指南</li></ul>',13)])])}const A=a(o,[["render",i]]);export{f as __pageData,A as default};
